import socket
import json
import time
import hashlib
import struct

class GameServer:
    def __init__(self, host='0.0.0.0', port=27015, max_response_size=512):
        self.host = host
        self.port = port
        self.max_response_size = max_response_size
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        
        self.players = [
            {"name": "Player1", "score": 100, "ping": 25},
            {"name": "Player2", "score": 85, "ping": 30},
            {"name": "Player3", "score": 120, "ping": 45},
        ]
        
        self.game_state = {
            "map": "de_dust2",
            "mode": "competitive",
            "max_players": 10,
            "current_players": len(self.players)
        }
        
        self.rate_limit = {}
        self.rate_limit_window = 10
        self.rate_limit_max_requests = 5
        
        self.challenge_cache = {}
        self.challenge_timeout = 30
        
    def generate_challenge(self, addr):
        timestamp = int(time.time())
        challenge_data = f"{addr[0]}:{addr[1]}:{timestamp}".encode()
        challenge = hashlib.sha256(challenge_data).digest()[:4]
        challenge_int = struct.unpack('I', challenge)[0]
        
        self.challenge_cache[addr] = {
            'challenge': challenge_int,
            'timestamp': timestamp
        }
        
        self.cleanup_old_challenges()
        
        return challenge_int
    
    def verify_challenge(self, addr, challenge):
        if addr not in self.challenge_cache:
            return False
        
        cached = self.challenge_cache[addr]
        current_time = int(time.time())
        
        if current_time - cached['timestamp'] > self.challenge_timeout:
            del self.challenge_cache[addr]
            return False
        
        return cached['challenge'] == challenge
    
    def cleanup_old_challenges(self):
        current_time = int(time.time())
        expired = [addr for addr, data in self.challenge_cache.items() 
                   if current_time - data['timestamp'] > self.challenge_timeout]
        for addr in expired:
            del self.challenge_cache[addr]
    
    def check_rate_limit(self, addr):
        current_time = time.time()
        client_key = addr[0]
        
        if client_key not in self.rate_limit:
            self.rate_limit[client_key] = []
        
        self.rate_limit[client_key] = [
            req_time for req_time in self.rate_limit[client_key]
            if current_time - req_time < self.rate_limit_window
        ]
        
        if len(self.rate_limit[client_key]) >= self.rate_limit_max_requests:
            return False
        
        self.rate_limit[client_key].append(current_time)
        return True
    
    def create_status_response(self):
        response = {
            "game_state": self.game_state,
            "players": self.players
        }
        return json.dumps(response).encode()
    
    def handle_request(self, data, addr):
        if not self.check_rate_limit(addr):
            error_response = b"RATE_LIMITED"
            self.sock.sendto(error_response, addr)
            return
        
        try:
            message = data.decode().strip()
            
            if message == "CHALLENGE":
                challenge = self.generate_challenge(addr)
                response = f"CHALLENGE:{challenge}".encode()
                self.sock.sendto(response, addr)
                return
            
            if message.startswith("STATUS:"):
                parts = message.split(":")
                if len(parts) != 2:
                    self.sock.sendto(b"INVALID_REQUEST", addr)
                    return
                
                try:
                    challenge = int(parts[1])
                except ValueError:
                    self.sock.sendto(b"INVALID_CHALLENGE", addr)
                    return
                
                if not self.verify_challenge(addr, challenge):
                    self.sock.sendto(b"CHALLENGE_FAILED", addr)
                    return
                
                del self.challenge_cache[addr]
                
                full_response = self.create_status_response()
                
                if len(full_response) > self.max_response_size:
                    num_chunks = (len(full_response) + self.max_response_size - 1) // self.max_response_size
                    
                    for i in range(num_chunks):
                        start = i * self.max_response_size
                        end = min((i + 1) * self.max_response_size, len(full_response))
                        chunk = full_response[start:end]
                        
                        header = struct.pack('!HH', i, num_chunks)
                        packet = header + chunk
                        self.sock.sendto(packet, addr)
                else:
                    self.sock.sendto(full_response, addr)
            else:
                self.sock.sendto(b"UNKNOWN_COMMAND", addr)
                
        except Exception as e:
            error_response = b"ERROR"
            self.sock.sendto(error_response, addr)
    
    def run(self):
        print(f"Game server listening on {self.host}:{self.port}")
        print(f"Max response size: {self.max_response_size} bytes")
        print(f"Rate limit: {self.rate_limit_max_requests} requests per {self.rate_limit_window} seconds")
        print(f"Challenge-response authentication enabled")
        
        while True:
            try:
                data, addr = self.sock.recvfrom(1024)
                self.handle_request(data, addr)
            except KeyboardInterrupt:
                print("\nShutting down server...")
                break
            except Exception as e:
                print(f"Error handling request: {e}")
        
        self.sock.close()

if __name__ == "__main__":
    server = GameServer(max_response_size=512)
    server.run()